  const condId = `COND-GUARD-${Date.now()}-${Math.floor(Math.random() * 1_000_000)}`;
  const actId  = `ACT-GUARD-${Date.now()}-${Math.floor(Math.random() * 1_000_000)}`;

  const nodes: StrategyNode[] = [
    {
      id:   condId,
      type: 'CONDITION',
      x:    20,
      y:    80,
      data: {
        label:       'Hard Drop',
        operator:    'drop',
        dropPercent: 10,
      },
    },
    {
      id:   actId,
      type: 'ACTION',
      x:    280,
      y:    80,
      data: {
        label:  'Emergency Exit',
        side:   'SELL',
        amount: 100,
      },
    },
  ];

  const connections: Connection[] = [
    { fromId: condId, toId: actId },
  ];

  return { nodes, connections };
}
